732	      case "tool_call": {
733	        const title = (up.title as string) ?? "tool";
734	        const startId = up.toolCallId as string | undefined;
735	        if (startId) (session._toolTitles ??= new Map()).set(startId, title);
736	        session.toolTimeline.push({
737	          id: startId ?? `__auto_${session.toolTimeline.length}`,
738	          name: title,
739	          status: "running",
740	          startedAt: Date.now(),
741	        });
742	        // Tier A precedingTools 唯一 push 維護點（避免 tool_call+update 兩處重複計數）。
743	        session._recentToolNames = appendToolName(session._recentToolNames ?? [], title);
744	        session._toolInFlight = true;
745	        petState("tool", title);
746	        session.onUpdate?.(session);
747	        break;
748	      }
749	      case "tool_call_update": {
750	        const status = up.status as string | undefined;
751	        const updId = up.toolCallId as string | undefined;
752	        // Adapter 可能在 tool_call 起始時只給殘缺 title（參數還在 stream），
753	        // 完整 title 之後才隨 update 補上——收到就回寫 timeline entry 與
754	        // _toolTitles，讓進度行和 log 都拿到完整工具名。
755	        const updTitle = typeof up.title === "string" && up.title ? up.title : undefined;
756	        let titleChanged = false;
757	        if (updTitle) {
758	          if (updId) (session._toolTitles ??= new Map()).set(updId, updTitle);
759	          let entry = updId
760	            ? session.toolTimeline.find((t) => t.id === updId)
761	            : undefined;
762	          if (!entry) {
763	            for (let i = session.toolTimeline.length - 1; i >= 0; i--) {
764	              if (session.toolTimeline[i].status === "running") {
765	                entry = session.toolTimeline[i];
766	                break;
767	              }
768	            }
769	          }
770	          if (entry && entry.name !== updTitle) {
771	            entry.name = updTitle;
772	            titleChanged = true;
773	          }
774	        }
775	        // Kiro 的 tool_call_update 只帶 opaque toolCallId、不帶 name。用綁定的
776	        // title 解析工具名；退而用 inline title，再退用 "tool"。
777	        const toolName =
778	          (updId ? session._toolTitles?.get(updId) : undefined) ??
779	          updTitle ??
780	          "tool";
781	        if (status === "completed") {
782	          markToolDone(session, updId, "completed");
783	          // A success clears any stale reflexion hint (fail streak is over).
784	          if (session.toolLog.length) session.toolLog = [];
785	          session._toolInFlight = false;
786	          session._consecutiveToolFails = 0;
787	          logEvent("tool_call", { name: toolName, status: "completed" }, { chatId: session.chatId });
788	          // Tier A seq observation：僅 ACP 路徑（Direct 由 tool-loop 的 Tier B rich 接手，避免雙記 BC-1）。
789	          // slice(0,-1) 排除「當前工具自身」（tool_call 已先 push title），對齊 rich 的「preceding 不含本 tool」語意。
790	          if (session.activeProvider === "acp") {
791	            recordSeqObservation({
792	              name: toolName,
793	              status: "completed",
794	              sessionId: session.sessionId,
795	              chatId: session.chatId,
796	              precedingTools: (session._recentToolNames ?? []).slice(0, -1),
797	            });
798	          }
799	          if (updId) session._toolTitles?.delete(updId);
800	          session.onUpdate?.(session);
801	        } else if (status === "failed") {
802	          markToolDone(session, updId, "failed");
803	          session._toolInFlight = false;
804	          session._consecutiveToolFails++;
805	          logEvent("tool_call", { name: toolName, status: "failed" }, { chatId: session.chatId });
806	          // Tier A seq observation：僅 ACP 路徑（Direct 失敗 tool 由 tool-loop catch 分支寫 rich）。
807	          if (session.activeProvider === "acp") {
808	            recordSeqObservation({
809	              name: toolName,
810	              status: "failed",
811	              sessionId: session.sessionId,
812	              chatId: session.chatId,
813	              precedingTools: (session._recentToolNames ?? []).slice(0, -1),
814	            });
815	          }
816	          if (updId) session._toolTitles?.delete(updId);
817	          if (session._consecutiveToolFails >= 2) {
818	            session.toolLog.push(
819	              `⚠️ [Reflexion hint] ${session._consecutiveToolFails} consecutive tool failures. ` +
820	              `STOP and diagnose: what assumption is wrong? Try a different approach.`
821	            );
822	          }
823	          session.onUpdate?.(session);
824	        } else if (titleChanged) {
825	          // in_progress 等中間更新：title 已回寫，刷新進度行顯示。
826	          // onUpdate 下游有 coalescing latch + 節流，高頻呼叫安全。
827	          session.onUpdate?.(session);
828	        }
829	        break;
830	      }
831	      default:
832	        // Ignore plan/user_message_chunk/etc. for the bridge.
833	        break;
834	    }

495	// 輸出 markdown 原文：sendRichMessageDraft 的 rich_message.markdown 收
496	// markdown（final 持久化的 trySendRichMessage 也是傳 markdown），不可餵
497	// renderReply 的 HTML。
498	export function renderDraftReply(
499	  session: ChatSession,
500	  parsers: ScheduleParsers,
501	  replyHeader?: string,
502	): string {
503	  // Header 是恆定前綴（第一幀到最後一幀都相同），放頭部不違反 draft
504	  // 動畫的 append-only 假設。有 header 時即使其餘全空也回傳 header，
505	  // 讓「我選擇了：X」立刻可見（而不是 server 原生 Thinking…）。
506	  const header = replyHeader ? replyHeader + "\n\n" : "";
507	  const raw = session.buffer || "";
508	  const stripped = transformReplyTokens(raw, parsers).text;
509	
510	  let thinkingBlock = "";
511	  if (session.thinkingBuffer) {
512	    const t = session.thinkingBuffer;
513	    const preview = t.length > 200 ? "…" + t.slice(-200) : t;
514	    thinkingBlock = "💭 " + preview.split("\n").join("\n> ");
515	  }
516	  const toolLines = toolPrefixLines(session);
517	  const tools = toolLines.length ? toolLines.join("\n") : "";
518	
519	  const statusTail = [thinkingBlock, tools].filter(Boolean).join("\n\n");
520	  const cursor = " ▍";
521	  const overhead = header.length + (statusTail ? statusTail.length + 2 : 0) + cursor.length;
522	  const bodyBudget = Math.max(TG_MAX - overhead, 200);
523	  let body = stripped;
524	  if (body.length > bodyBudget) {
525	    body = "…" + body.slice(-bodyBudget);
526	  }
527	  const head = body ? body + cursor : "";
528	  // 全空（且無 header）→ 回空字串，trySendDraft 會送 text=undefined，server 顯示原生 "Thinking…"
529	  const joined = [head, statusTail].filter(Boolean).join("\n\n");
530	  if (!joined) return replyHeader ?? "";
531	  return header + joined;
532	}
